import asyncioimport osimport pytestimport requestsfrom dotenv import load_dotenvfrom langchain_anthropic import ChatAnthropicfrom ragas import SingleTurnSamplefrom ragas.llms import LangchainLLMWrapperfrom ragas.metrics._context_precision import LLMContextPrecisionWithoutReferenceload_dotenv()@pytest.mark.asyncioasync def test_context_precision():    if not os.getenv("ANTHROPIC_API_KEY"):        pytest.skip("ANTHROPIC_API_KEY is not set")    model_name = os.getenv("ANTHROPIC_MODEL", "claude-sonnet-4-6")    print(f"Using Anthropic model: {model_name}", flush=True)    llm_model = ChatAnthropic(temperature=0, model_name=model_name)    langchain_llm = LangchainLLMWrapper(llm_model)    context_precision = LLMContextPrecisionWithoutReference(llm=langchain_llm)    question = "How many articles are there in the Selenium Webdriver course?"    response_dict = requests.post(        "https://rahulshettyacademy.com/rag-llm/ask",        json={            "question": question,            "chat_history": []        }    ).json()    print(f"The response is: {response_dict}")    # feed data    sample = SingleTurnSample(        user_input=question,        response=response_dict["answer"],        retrieved_contexts=[            response_dict["retrieved_docs"][0]["page_content"],            response_dict["retrieved_docs"][1]["page_content"],            response_dict["retrieved_docs"][2]["page_content"],            response_dict["retrieved_docs"][3]["page_content"]        ],    )    print("Computing context precision score...", flush=True)    try:        score = await asyncio.wait_for(            context_precision.single_turn_ascore(sample),            timeout=30,        )    except asyncio.TimeoutError as exc:        pytest.fail("Timed out waiting for context precision score (30s)")    print(f"The score is: {score}")    assert score is not None    assert 0 <= score <= 1